script4 = r'''
(() => {'use strict';const root=document.getElementById('lesson4View'),$=s=>root.querySelector(s),$$=s=>[...root.querySelectorAll(s)];const set=(k,v)=>{window.__academyMemory=window.__academyMemory||{};window.__academyMemory[k]=v;try{localStorage.setItem(k,v)}catch{}};let progress=new Set();const items=[{id:'system',label:'System 规则',tokens:180,type:'system',text:'公司制度助手；不知道时不要猜'},{id:'user',label:'当前用户消息',tokens:65,type:'user',text:'那它什么时候能用？'},{id:'history',label:'必要历史',tokens:220,type:'history',text:'上一轮讨论：试用期员工年假方案'},{id:'document',label:'公司制度',tokens:430,type:'document',text:'转正后次月可使用年假'},{id:'irrelevant',label:'无关聊天',tokens:520,type:'history',text:'午饭、天气和其他项目闲聊'}];let selected=new Set(['user']),success=false;
function mark(k){progress.add(k);$('#l4Mastery').textContent=`掌握 ${progress.size}/4${progress.size>=4?' ✓':''}`;if(['lab','quiz'].every(x=>progress.has(x))){set('ai-academy-l4-content','true');$('#l4ExamButton').disabled=false;$('#l4ExamButton').textContent='参加第 4 课考试'}}
$$('[data-l4-go]').forEach(b=>b.onclick=()=>document.getElementById(b.dataset.l4Go)?.scrollIntoView({behavior:'smooth'}));$$('[data-l4-pred]').forEach(b=>b.onclick=()=>{if($('#l4-lab').classList.contains('unlocked'))return;$$('[data-l4-pred]').forEach(x=>{x.disabled=true;x.classList.toggle('selected',x===b)});const ok=b.dataset.l4Pred==='history';$('#l4PredictionResult').className=`gate-result ${ok?'good':'miss'}`;$('#l4PredictionResult').textContent=ok?'✓ 对。模型只看本次请求实际包含的内容。':'答案已记录。下面亲手构造本次请求。';$('#l4-lab').classList.add('unlocked');render()});
function renderShelf(){$('#l4Shelf').innerHTML='<div class="v3-pane-title"><b>可发送内容</b><span>点击加入/移除</span></div>'+items.map(i=>`<button class="message-card ${selected.has(i.id)?'selected':''}" data-item="${i.id}" type="button"><b>${i.label}</b><small>${i.tokens} tokens · ${i.text}</small></button>`).join('');$$('[data-item]').forEach(b=>b.onclick=()=>{const id=b.dataset.item;if(id==='user')return;selected.has(id)?selected.delete(id):selected.add(id);render()})}
function buildWindow(){const turns=Number($('#l4Turns').value),output=Number($('#l4Output').value);let dynamic=[];for(let i=0;i<turns;i++)dynamic.push({id:'turn'+i,label:`历史轮 ${i+1}`,tokens:90,type:'history',text:i===0?'用户问过试用期年假':'无关的上一轮闲聊'});let list=[...items.filter(i=>selected.has(i.id)),...dynamic];const totalInput=list.reduce((s,i)=>s+i.tokens,0),limit=1600-output;let overflow=Math.max(0,totalInput-limit),evicted=new Set();for(const i of list){if(overflow<=0)break;if(i.id==='system'||i.id==='user')continue;overflow-=i.tokens;evicted.add(i.id)}const used=totalInput+output;$('#l4TokenText').textContent=`${used} / 1600`;$('#l4TokenFill').style.width=`${Math.min(100,used/16)}%`;$('#l4TokenFill').classList.toggle('warn',used>1600);$('#l4Window').innerHTML=list.map(i=>`<div class="context-item ${i.type} ${evicted.has(i.id)?'evicted':''}"><b>${i.label}</b><br>${i.text}<br><small>${i.tokens} tokens${evicted.has(i.id)?' · 已出窗':''}</small></div>`).join('');return{list,evicted,used,output}}
function render(){renderShelf();$('#l4TurnsText').textContent=$('#l4Turns').value;$('#l4OutputText').textContent=$('#l4Output').value;buildWindow()}
$('#l4Turns').oninput=render;$('#l4Output').oninput=render;$('#l4Clear').onclick=()=>{selected=new Set(['user']);$('#l4Turns').value=0;render()};$('#l4Run').onclick=()=>{const {evicted,used,output}=buildWindow();const has=id=>selected.has(id)&&!evicted.has(id);let msg;if(!has('history'))msg='模型仍不知道“它”指什么：必要历史缺失或已出窗。';else if(!has('system'))msg='模型理解对象了，但没有“不知道时不要猜”的行为规则。';else if(!has('document'))msg='模型知道在问年假，却没有公司制度事实，无法回答何时可用。';else if(selected.has('irrelevant')||used>1600)msg='请求塞入太多无关内容，关键历史被挤出或没有输出空间。';else if(output<250)msg='输入完整，但给回答预留的输出空间太小，可能被截断。';else{msg='✓ 回答：试用期年假方案在转正后的次月可以使用。';success=true;$('#l4-reveal').classList.add('reveal-unlocked');mark('lab');AcademyArtifacts.set('messages',{system:'公司制度助手；不知道时不要猜',history:['上一轮讨论：试用期员工年假方案'],user:'那它什么时候能用？',context:'转正后次月可使用年假',outputBudget:output});setTimeout(()=>$('#l4-reveal').scrollIntoView({behavior:'smooth'}),350)}$('#l4Result').className=`v3-result ${success?'good':'bad'}`;$('#l4Result').textContent=msg};
const prev=AcademyArtifacts.get('tsSource');$('#l4PreviousArtifact').textContent=prev?'已读取：上一课保存的 TypeScript 调用骨架。':'尚未找到产物；不影响本课演示。';$$('#l4Quiz .quiz-option').forEach(b=>b.onclick=()=>{const ok=b.dataset.correct==='true';if(ok){$$('#l4Quiz .quiz-option').forEach(x=>x.disabled=true);b.classList.add('correct');$('#l4QuizFeedback').className='quiz-feedback good';$('#l4QuizFeedback').textContent='✓ 对。只补必要历史，不是把全部聊天都塞进去。';mark('quiz')}else{b.classList.add('wrong');$('#l4QuizFeedback').className='quiz-feedback bad';$('#l4QuizFeedback').textContent='还不对，可以继续选择。';setTimeout(()=>b.classList.remove('wrong'),500)}});render();})();
'''

script6 = r'''
(() => {'use strict';const root=document.getElementById('lesson6View'),$=s=>root.querySelector(s),$$=s=>[...root.querySelectorAll(s)];const set=(k,v)=>{window.__academyMemory=window.__academyMemory||{};window.__academyMemory[k]=v;try{localStorage.setItem(k,v)}catch{}};let progress=new Set(),order=['complaint','refund_query','refund'];const cases=[['退款还没到账，问了三次','refund_query'],['服务态度太差，不涉及退款','complaint'],['我要申请退款','refund'],['帮我处理一下','unknown'],['退款什么时候退，客服也不回','refund_query'],['商品损坏，要求退款','refund']];
function mark(k){progress.add(k);$('#l6Mastery').textContent=`掌握 ${progress.size}/4${progress.size>=4?' ✓':''}`;if(['lab','quiz'].every(x=>progress.has(x))){set('ai-academy-l6-content','true');$('#l6ExamButton').disabled=false;$('#l6ExamButton').textContent='参加第 6 课考试'}}
$$('[data-l6-go]').forEach(b=>b.onclick=()=>document.getElementById(b.dataset.l6Go)?.scrollIntoView({behavior:'smooth'}));$$('[data-l6-pred]').forEach(b=>b.onclick=()=>{if($('#l6-lab').classList.contains('unlocked'))return;$$('[data-l6-pred]').forEach(x=>{x.disabled=true;x.classList.toggle('selected',x===b)});const ok=b.dataset.l6Pred==='business';$('#l6PredictionResult').className=`gate-result ${ok?'good':'miss'}`;$('#l6PredictionResult').textContent=ok?'✓ 对。优先级必须来自业务，而不是模型常识。':'答案已记录。下面看规则顺序如何造成真实误路由。';$('#l6-lab').classList.add('unlocked');renderRules();run(false)});
function renderRules(){$('#l6Rules').innerHTML=order.map((r,i)=>`<div class="rule-row"><i>${i+1}</i><b>${{complaint:'检测投诉情绪',refund_query:'检测退款到账/进度',refund:'检测退款申请'}[r]}</b><span class="rule-controls"><button data-up="${i}" type="button">↑</button><button data-down="${i}" type="button">↓</button></span></div>`).join('');$$('[data-up]').forEach(b=>b.onclick=()=>{const i=+b.dataset.up;if(i>0){[order[i-1],order[i]]=[order[i],order[i-1]];renderRules();run(false)}});$$('[data-down]').forEach(b=>b.onclick=()=>{const i=+b.dataset.down;if(i<order.length-1){[order[i+1],order[i]]=[order[i],order[i+1]];renderRules();run(false)}})}
function classify(text){for(const r of order){if(r==='complaint'&&/(太差|不回|问了三次)/.test(text)&&!($('#l6ArrivalPriority').checked&&/(到账|什么时候退)/.test(text)))return'complaint';if(r==='refund_query'&&/(到账|什么时候退|进度)/.test(text))return'refund_query';if(r==='refund'&&/(申请退款|要求退款|商品损坏)/.test(text))return'refund'}return $('#l6Unknown').checked?'unknown':'refund'}
function run(scroll=true){const results=cases.map(([t,e])=>[t,e,classify(t)]),ok=results.filter(x=>x[1]===x[2]).length;$('#l6Rows').innerHTML=results.map(([t,e,a])=>`<tr><td>${t}</td><td>${e}</td><td>${a}</td><td class="${e===a?'pass':'fail'}">${e===a?'✓':'✗'}</td></tr>`).join('');$('#l6Accuracy').textContent=`${ok}/6`;$('#l6Boundary').textContent=results[0][2]==='refund_query'&&results[4][2]==='refund_query'?'PASS':'FAIL';$('#l6UnknownMetric').textContent=results[3][2]==='unknown'?'PASS':'FAIL';$('#l6Conflict').textContent=order[0]==='refund_query'||$('#l6ArrivalPriority').checked?'已声明':'未声明';$('#l6RouteFlow').innerHTML=order.map((r,i)=>`<span class="route-node ${i===0?'active':''}">${i+1}. ${r}</span>`).join('<span>→</span>');if(ok===6){$('#l6-reveal').classList.add('reveal-unlocked');$('#l6RuleHint').className='v3-result good';$('#l6RuleHint').textContent='✓ 六个案例全部正确。规则边界和失败出口已经可执行。';mark('lab');const rules={order:[...order],allowUnknown:$('#l6Unknown').checked,arrivalPriority:$('#l6ArrivalPriority').checked,cases};AcademyArtifacts.set('classificationRules',rules);if(scroll)setTimeout(()=>$('#l6-reveal').scrollIntoView({behavior:'smooth'}),350)}else{$('#l6RuleHint').className='v3-result bad';$('#l6RuleHint').textContent='仍有误路由。尝试把退款进度提前、开启 unknown，并明确到账优先。'}}
$('#l6Run').onclick=()=>run(true);$('#l6Unknown').onchange=()=>run(false);$('#l6ArrivalPriority').onchange=()=>run(false);$('#l6Reset').onclick=()=>{order=['complaint','refund_query','refund'];$('#l6Unknown').checked=false;$('#l6ArrivalPriority').checked=false;renderRules();run(false)};const prompt=AcademyArtifacts.get('promptV1');$('#l6PromptArtifact').textContent=prompt?'已读取 Prompt v1；本课会把它升级成明确的决策规则。':'尚未找到 Prompt v1；不影响演示。';$$('#l6Quiz .quiz-option').forEach(b=>b.onclick=()=>{const ok=b.dataset.correct==='true';if(ok){$$('#l6Quiz .quiz-option').forEach(x=>x.disabled=true);b.classList.add('correct');$('#l6QuizFeedback').className='quiz-feedback good';$('#l6QuizFeedback').textContent='✓ 对。边界、优先级和 unknown 都必须明确。';mark('quiz')}else{b.classList.add('wrong');$('#l6QuizFeedback').className='quiz-feedback bad';$('#l6QuizFeedback').textContent='还不对，可以继续选择。';setTimeout(()=>b.classList.remove('wrong'),500)}});renderRules();})();
'''

script7 = r'''
(() => {'use strict';const root=document.getElementById('lesson7View'),$=s=>root.querySelector(s),$$=s=>[...root.querySelectorAll(s)];const set=(k,v)=>{window.__academyMemory=window.__academyMemory||{};window.__academyMemory[k]=v;try{localStorage.setItem(k,v)}catch{}};let progress=new Set(),index=0,passed=new Set();const tasks=[{id:'syntax',title:'Markdown 包裹',desc:'返回被 ```json 包裹，JSON.parse 失败',value:'```json\n{\n  "intent": "refund_query",\n  "confidence": 0.91,\n  "reason": "询问到账时间"\n}\n```',hint:'删除 Markdown 代码围栏，只保留 JSON 对象。'}, {id:'schema',title:'字段类型错误',desc:'confidence 被返回为字符串',value:'{\n  "intent": "refund_query",\n  "confidence": "high",\n  "reason": "询问到账时间"\n}',hint:'confidence 必须是 0 到 1 之间的数字。'}, {id:'business',title:'业务组合错误',desc:'unknown 却给出 0.98 置信度',value:'{\n  "intent": "unknown",\n  "confidence": 0.98,\n  "reason": "信息不足"\n}',hint:'unknown 时置信度不能高于 0.5。'}];
function mark(k){progress.add(k);$('#l7Mastery').textContent=`掌握 ${progress.size}/4${progress.size>=4?' ✓':''}`;if(['lab','quiz'].every(x=>progress.has(x))){set('ai-academy-l7-content','true');$('#l7ExamButton').disabled=false;$('#l7ExamButton').textContent='参加第 7 课考试'}}
$$('[data-l7-go]').forEach(b=>b.onclick=()=>document.getElementById(b.dataset.l7Go)?.scrollIntoView({behavior:'smooth'}));$$('[data-l7-pred]').forEach(b=>b.onclick=()=>{if($('#l7-lab').classList.contains('unlocked'))return;$$('[data-l7-pred]').forEach(x=>{x.disabled=true;x.classList.toggle('selected',x===b)});const ok=b.dataset.l7Pred==='business';$('#l7PredictionResult').className=`gate-result ${ok?'good':'miss'}`;$('#l7PredictionResult').textContent=ok?'✓ 对。语法和类型都合法，问题在业务组合。':'答案已记录。下面让三道门分别给出失败原因。';$('#l7-lab').classList.add('unlocked');render()});
function render(){$('#l7Presets').innerHTML=tasks.map((t,i)=>`<button class="json-preset ${i===index?'active':''}" type="button" disabled><b>${i<index?'✓ ':''}${t.title}</b><small>${t.desc}</small></button>`).join('');$('#l7Editor').value=tasks[index]?.value||'{\n  "intent":"refund_query",\n  "confidence":0.91,\n  "reason":"询问到账时间"\n}';['Json','Schema','Business'].forEach(x=>{$('#l7Gate'+x).className='gate-box';$('small',$('#l7Gate'+x)).textContent='还没运行'});$('#l7Result').textContent=tasks[index]?`当前任务：${tasks[index].hint}`:'全部故障已修复。'}
function setGate(id,ok,msg){const el=$('#'+id);el.className=`gate-box ${ok?'pass':'fail'}`;$('small',el).textContent=msg}
$('#l7Run').onclick=()=>{let obj;try{obj=JSON.parse($('#l7Editor').value);setGate('l7GateJson',true,'JSON 语法通过')}catch(e){setGate('l7GateJson',false,'无法解析：'+e.message.split('\n')[0]);setGate('l7GateSchema',false,'未执行');setGate('l7GateBusiness',false,'未执行');$('#l7Result').className='v3-result bad';$('#l7Result').textContent=tasks[index].hint;return}const schemaOk=['refund','refund_query','complaint','unknown'].includes(obj.intent)&&typeof obj.confidence==='number'&&obj.confidence>=0&&obj.confidence<=1&&typeof obj.reason==='string';setGate('l7GateSchema',schemaOk,schemaOk?'字段、类型、枚举和范围通过':'需要 intent 枚举、0~1 数字 confidence、字符串 reason');if(!schemaOk){setGate('l7GateBusiness',false,'未执行');$('#l7Result').className='v3-result bad';$('#l7Result').textContent=tasks[index].hint;return}const businessOk=!(obj.intent==='unknown'&&obj.confidence>0.5);setGate('l7GateBusiness',businessOk,businessOk?'业务组合合理':'unknown 不能同时极高置信度');if(!businessOk){$('#l7Result').className='v3-result bad';$('#l7Result').textContent=tasks[index].hint;return}passed.add(tasks[index].id);$('#l7Result').className='v3-result good';$('#l7Result').textContent='✓ 当前故障已修复，进入下一层。';index++;['l7M1','l7M2','l7M3'].forEach((id,i)=>$('#'+id).textContent=i<index?'✓':'○');if(index<tasks.length)setTimeout(render,350);else{$('#l7M4').textContent='✓';$('#l7-reveal').classList.add('reveal-unlocked');mark('lab');AcademyArtifacts.set('outputSchema',{intent:['refund','refund_query','complaint','unknown'],confidence:'number 0..1',reason:'string',businessRule:'unknown confidence <= 0.5'});setTimeout(()=>$('#l7-reveal').scrollIntoView({behavior:'smooth'}),350)}};
$('#l7Reset').onclick=render;const rules=AcademyArtifacts.get('classificationRules');$('#l7RulesArtifact').textContent=rules?'已读取：退款进度优先、unknown 出口和规则顺序。':'尚未找到规则产物；不影响演示。';$$('#l7Quiz .quiz-option').forEach(b=>b.onclick=()=>{const ok=b.dataset.correct==='true';if(ok){$$('#l7Quiz .quiz-option').forEach(x=>x.disabled=true);b.classList.add('correct');$('#l7QuizFeedback').className='quiz-feedback good';$('#l7QuizFeedback').textContent='✓ 对。类型正确和业务合理是两层。';mark('quiz')}else{b.classList.add('wrong');$('#l7QuizFeedback').className='quiz-feedback bad';$('#l7QuizFeedback').textContent='还不对，可以继续选择。';setTimeout(()=>b.classList.remove('wrong'),500)}});})();
'''

script8 = r'''
(() => {'use strict';const root=document.getElementById('lesson8View'),$=s=>root.querySelector(s),$$=s=>[...root.querySelectorAll(s)];const set=(k,v)=>{window.__academyMemory=window.__academyMemory||{};window.__academyMemory[k]=v;try{localStorage.setItem(k,v)}catch{}};let progress=new Set(),selected=new Set();const points=[{id:'query',label:'当前邮件',x:50,y:50,tokens:0,kind:'query'},{id:'boundary',label:'不满+问到账',x:58,y:45,tokens:105,kind:'boundary'},{id:'simple1',label:'退款进度查询',x:70,y:38,tokens:90,kind:'normal'},{id:'simple2',label:'退款进度查询②',x:73,y:40,tokens:88,kind:'normal'},{id:'contrast',label:'纯服务投诉',x:31,y:66,tokens:100,kind:'normal'},{id:'failure',label:'信息不足→unknown',x:44,y:78,tokens:92,kind:'failure'},{id:'refund',label:'新申请退款',x:22,y:40,tokens:96,kind:'normal'},{id:'noise',label:'营销邮件',x:14,y:18,tokens:70,kind:'normal'}];
function mark(k){progress.add(k);$('#l8Mastery').textContent=`掌握 ${progress.size}/4${progress.size>=4?' ✓':''}`;if(['lab','quiz'].every(x=>progress.has(x))){set('ai-academy-l8-content','true');$('#l8ExamButton').disabled=false;$('#l8ExamButton').textContent='参加第 8 课考试'}}
$$('[data-l8-go]').forEach(b=>b.onclick=()=>document.getElementById(b.dataset.l8Go)?.scrollIntoView({behavior:'smooth'}));$$('[data-l8-pred]').forEach(b=>b.onclick=()=>{if($('#l8-lab').classList.contains('unlocked'))return;$$('[data-l8-pred]').forEach(x=>{x.disabled=true;x.classList.toggle('selected',x===b)});const ok=b.dataset.l8Pred==='no';$('#l8PredictionResult').className=`gate-result ${ok?'good':'miss'}`;$('#l8PredictionResult').textContent=ok?'✓ 对。示例只参与本次上下文，不会永久改权重。':'答案已记录。下面在语义地图里挑示例。';$('#l8-lab').classList.add('unlocked');render()});
function render(){const map=$('#l8Map');map.querySelectorAll('.semantic-point').forEach(x=>x.remove());points.forEach(p=>{const b=document.createElement('button');b.className=`semantic-point ${p.kind} ${selected.has(p.id)?'selected':''}`;b.style.left=p.x+'%';b.style.top=p.y+'%';b.textContent=p.label+(p.tokens?` · ${p.tokens}`:'');b.disabled=p.id==='query';b.onclick=()=>toggle(p);map.appendChild(b)});metrics()}
function toggle(p){if(selected.has(p.id))selected.delete(p.id);else{const used=[...selected].reduce((s,id)=>s+points.find(x=>x.id===id).tokens,0);if(selected.size>=3||used+p.tokens>300)return;selected.add(p.id)}render()}
function metrics(){const arr=[...selected].map(id=>points.find(x=>x.id===id)),used=arr.reduce((s,p)=>s+p.tokens,0);$('#l8Budget').textContent=`${used} / 300`;const rel=arr.length?Math.round(arr.reduce((s,p)=>s+Math.max(0,100-Math.hypot(p.x-50,p.y-50)*3),0)/arr.length):0;let minDist=100;if(arr.length>1)for(let i=0;i<arr.length;i++)for(let j=i+1;j<arr.length;j++)minDist=Math.min(minDist,Math.hypot(arr[i].x-arr[j].x,arr[i].y-arr[j].y));const diversity=arr.length<2?0:Math.min(100,Math.round(minDist*5));const boundary=selected.has('boundary'),failure=selected.has('failure');$('#l8Rel').textContent=`相关性：${rel||'—'}${rel?'%':''}`;$('#l8Div').textContent=`多样性：${diversity||'—'}${diversity?'%':''}`;$('#l8Boundary').textContent=`边界例：${boundary?'已覆盖':'未覆盖'}`;$('#l8Failure').textContent=`失败出口：${failure?'已覆盖':'未覆盖'}`;[$('#l8Boundary'),$('#l8Failure')].forEach(x=>x.classList.toggle('pass',/已覆盖/.test(x.textContent)));return{arr,used,rel,diversity,boundary,failure}}
$('#l8Run').onclick=()=>{const m=metrics(),hasContrast=selected.has('contrast');const ok=selected.size===3&&m.boundary&&m.failure&&hasContrast;if(ok){$('#l8Result').className='v3-result good';$('#l8Result').textContent='✓ 示例集同时覆盖当前边界、对比类别和信息不足出口。';$('#l8-reveal').classList.add('reveal-unlocked');mark('lab');AcademyArtifacts.set('fewShotExamples',m.arr.map(p=>({id:p.id,label:p.label,tokens:p.tokens,kind:p.kind})));setTimeout(()=>$('#l8-reveal').scrollIntoView({behavior:'smooth'}),350)}else{$('#l8Result').className='v3-result bad';$('#l8Result').textContent='还不够：需要“边界例 + 纯投诉对比例 + unknown 失败例”，且不能超过预算。'}};$('#l8Reset').onclick=()=>{selected.clear();render();$('#l8Result').className='v3-result';$('#l8Result').textContent='点击地图中的示例。圆形是普通例，虚线是边界例，方形是失败例。'};const schema=AcademyArtifacts.get('outputSchema');$('#l8SchemaArtifact').textContent=schema?'已读取：intent、confidence、reason 和 unknown 业务规则。':'尚未找到 Schema 产物；不影响演示。';$$('#l8Quiz .quiz-option').forEach(b=>b.onclick=()=>{const ok=b.dataset.correct==='true';if(ok){$$('#l8Quiz .quiz-option').forEach(x=>x.disabled=true);b.classList.add('correct');$('#l8QuizFeedback').className='quiz-feedback good';$('#l8QuizFeedback').textContent='✓ 对。典型、失败和歧义共同覆盖行为边界。';mark('quiz')}else{b.classList.add('wrong');$('#l8QuizFeedback').className='quiz-feedback bad';$('#l8QuizFeedback').textContent='还不对，可以继续选择。';setTimeout(()=>b.classList.remove('wrong'),500)}});})();
'''

script9 = r'''
(() => {'use strict';const root=document.getElementById('lesson9View'),$=s=>root.querySelector(s),$$=s=>[...root.querySelectorAll(s)];const set=(k,v)=>{window.__academyMemory=window.__academyMemory||{};window.__academyMemory[k]=v;try{localStorage.setItem(k,v)}catch{}};let progress=new Set(),filter=false;let cases=[{name:'普通退款申请',text:'我要退款',expected:'refund',v1:'refund'},{name:'询问退款到账',text:'退款什么时候到账',expected:'refund_query',v1:'refund'},{name:'不满+到账查询',text:'问了三次还没到账',expected:'refund_query',v1:'complaint'},{name:'纯服务投诉',text:'客服态度太差',expected:'complaint',v1:'complaint'},{name:'信息不足',text:'帮我处理一下',expected:'unknown',v1:'refund'},{name:'退款缺订单号',text:'我要退款，但没找到订单号',expected:'refund',v1:'refund'},{name:'普通订单查询',text:'查订单状态',expected:'query',v1:'query'},{name:'混合多意图',text:'客服很差，退款何时到账',expected:'refund_query',v1:'complaint'}];
const defaultPrompt=`类别：refund / refund_query / complaint / query / unknown\n规则：询问到账时间优先 refund_query。\n信息不足返回 unknown。\n退款申请缺订单号时返回 unknown。`;
function mark(k){progress.add(k);$('#l9Mastery').textContent=`掌握 ${progress.size}/4${progress.size>=4?' ✓':''}`;if(['lab','quiz'].every(x=>progress.has(x))){set('ai-academy-l9-content','true');$('#l9ExamButton').disabled=false;$('#l9ExamButton').textContent='参加第 9 课考试'}}
$$('[data-l9-go]').forEach(b=>b.onclick=()=>document.getElementById(b.dataset.l9Go)?.scrollIntoView({behavior:'smooth'}));$$('[data-l9-pred]').forEach(b=>b.onclick=()=>{if($('#l9-lab').classList.contains('unlocked'))return;$$('[data-l9-pred]').forEach(x=>{x.disabled=true;x.classList.toggle('selected',x===b)});const ok=b.dataset.l9Pred==='dataset';$('#l9PredictionResult').className=`gate-result ${ok?'good':'miss'}`;$('#l9PredictionResult').textContent=ok?'✓ 对。平均分可能掩盖关键回归。':'答案已记录。下面用同一 Dataset 直接比较。';$('#l9-lab').classList.add('unlocked')});
function classify(text,prompt){if(/到账|何时到账/.test(text)&&/到账时间优先/.test(prompt))return'refund_query';if(/客服态度|客服很差/.test(text))return'complaint';if(/订单状态/.test(text))return'query';if(/帮我处理/.test(text)&&/信息不足返回 unknown/.test(prompt))return'unknown';if(/我要退款/.test(text)){if(/没找到订单号/.test(text)&&/缺订单号时返回 unknown/.test(prompt))return'unknown';return'refund'}return'unknown'}
function run(){const p=$('#l9Prompt').value;const rows=cases.map(c=>({...c,current:classify(c.text,p)}));const correct=rows.filter(r=>r.current===r.expected).length,reg=rows.filter(r=>r.v1===r.expected&&r.current!==r.expected).length;$('#l9Accuracy').textContent=`${Math.round(correct/rows.length*100)}%`;$('#l9SchemaRate').textContent='100%';$('#l9Regression').textContent=reg;$('#l9Rows').innerHTML=rows.filter(r=>!filter||r.current!==r.expected||r.v1!==r.expected).map(r=>`<tr class="${r.current===r.expected?'fixed':'regression'}"><td>${r.name}</td><td>${r.expected}</td><td>${r.v1}</td><td>${r.current}</td><td>${r.current===r.expected?'✓':'✗'}</td></tr>`).join('');if(correct===rows.length){$('#l9Explain').className='v3-result good';$('#l9Explain').textContent='✓ 全量案例通过，且没有旧案例回归。可以形成 Prompt v3。';$('#l9-reveal').classList.add('reveal-unlocked');mark('lab');AcademyArtifacts.merge({promptV2:{text:p,version:'v3',createdAt:new Date().toISOString()},evaluationReport:{total:rows.length,accuracy:1,regressions:0,rows},evaluationDataset:cases});setTimeout(()=>$('#l9-reveal').scrollIntoView({behavior:'smooth'}),350)}else{$('#l9Explain').className='v3-result bad';$('#l9Explain').textContent=`当前 ${correct}/${rows.length} 通过，${reg} 个回归。提示：删除“退款申请缺订单号时返回 unknown”，改成缺字段只写进 reason。`}}
$('#l9Run').onclick=run;$('#l9Filter').onclick=()=>{filter=!filter;$('#l9Filter').classList.toggle('on',filter);run()};$('#l9AddCase').onclick=()=>{const text=$('#l9NewInput').value.trim(),expected=$('#l9NewExpected').value.trim();if(!text||!expected)return;cases.push({name:'新增边界例',text,expected,v1:'unknown'});$('#l9NewInput').value='';$('#l9NewExpected').value='';run()};$('#l9Prompt').value=defaultPrompt;const ex=AcademyArtifacts.get('fewShotExamples');$('#l9FewShotArtifact').textContent=ex?`已读取 ${ex.length} 个示例；它们会成为当前 Prompt 的 Few-shot 部分。`:'尚未找到 Few-shot 产物；不影响评估演示。';$$('#l9Quiz .quiz-option').forEach(b=>b.onclick=()=>{const ok=b.dataset.correct==='true';if(ok){$$('#l9Quiz .quiz-option').forEach(x=>x.disabled=true);b.classList.add('correct');$('#l9QuizFeedback').className='quiz-feedback good';$('#l9QuizFeedback').textContent='✓ 对。固定数据集、版本和回退能力缺一不可。';mark('quiz')}else{b.classList.add('wrong');$('#l9QuizFeedback').className='quiz-feedback bad';$('#l9QuizFeedback').textContent='还不对，可以继续选择。';setTimeout(()=>b.classList.remove('wrong'),500)}});})();
'''

