# Enhancement script appended after all scripts
enhancement_script = r'''
(() => {'use strict';
const A=window.AcademyArtifacts;
// Lesson 1 repeated-run distribution
const r1=document.getElementById('l1DistRun');if(r1)r1.addEventListener('click',()=>{const rules=document.getElementById('l1DistRules').checked,schema=document.getElementById('l1DistSchema').checked;const vals=rules?[85,10,5]:[48,32,20];['A','B','C'].forEach((x,i)=>{document.getElementById('l1Dist'+x).style.width=vals[i]+'%';document.getElementById('l1Dist'+x+'T').textContent=vals[i]+'%'});document.getElementById('l1FormatPass').textContent=schema?'100%':'55%';document.getElementById('l1DistExplain').className='v3-result good';document.getElementById('l1DistExplain').textContent=rules?'业务规则让分类分布收敛；'+(schema?'Schema 另外让格式稳定。':'但返回格式仍可能变化。'):'没有业务规则时，模型在三个相近类别间摇摆。Schema 即使打开，也只固定格式。';A.set('businessRisk',{task:'email intent',risk:'probabilistic classification',needs:['rules','schema','business validation','fallback'],distribution:vals})});
// Lesson 2 condition mixer
const conditions=[['spring','已有 Spring Boot 系统',{java:28,python:-4,ts:-5}],['javaTeam','团队只熟悉 Java',{java:24,python:-8,ts:-9}],['science','需要科学计算/研究',{java:-5,python:32,ts:-4}],['online','必须浏览器在线运行',{java:-7,python:-3,ts:25}],['shared','前后端共享类型',{java:-2,python:-4,ts:22}],['langchain','课程主线 LangChain JS',{java:-5,python:3,ts:26}],['mcp','开发 MCP Server',{java:4,python:10,ts:18}],['fastAlgo','快速验证算法',{java:-6,python:24,ts:2}]];const box=document.getElementById('l2Conditions');if(box){box.innerHTML=conditions.map(c=>`<label class="condition-toggle"><span>${c[1]}</span><input type="checkbox" data-cond="${c[0]}"></label>`).join('');function renderMix(){let s={java:50,python:50,ts:50};box.querySelectorAll('input:checked').forEach(i=>{const c=conditions.find(x=>x[0]===i.dataset.cond);Object.keys(s).forEach(k=>s[k]+=c[2][k])});Object.keys(s).forEach(k=>s[k]=Math.max(5,Math.min(100,s[k])));[['Java','java'],['Python','python'],['Ts','ts']].forEach(([id,k])=>{document.getElementById('l2Mix'+id).style.width=s[k]+'%';document.getElementById('l2Mix'+id+'T').textContent=s[k]});const winner=Object.entries(s).sort((a,b)=>b[1]-a[1])[0][0];document.getElementById('l2MixExplain').textContent=`当前更匹配：${{java:'Java',python:'Python',ts:'TypeScript'}[winner]}。这不是总榜，只是当前条件的结果。`;return{s,winner,conditions:[...box.querySelectorAll('input:checked')].map(i=>i.dataset.cond)}}box.onchange=renderMix;renderMix();document.getElementById('l2SaveDecision').onclick=()=>{const d=renderMix();A.set('languageDecision',d);document.getElementById('l2MixExplain').className='v3-result good';document.getElementById('l2MixExplain').textContent+=' 已保存到课程产物账本。'}}
// Lesson 5 counterfactual deletion + Prompt artifact
const counter=document.getElementById('l5CounterBlocks');if(counter){const text={task:'删除任务：模型不知道要分类还是摘要。',context:'删除业务上下文：类别含义重新依赖模型常识。',rules:'删除判断规则：边界输入开始摇摆。',output:'删除输出格式：后端重新拿到一段散文。',failure:'删除失败策略：信息不足时模型被迫猜。'};counter.querySelectorAll('[data-counter]').forEach(b=>b.onclick=()=>{b.classList.toggle('off');const off=[...counter.querySelectorAll('.off')].map(x=>x.dataset.counter);document.getElementById('l5CounterResult').className=`v3-result ${off.length?'bad':'good'}`;document.getElementById('l5CounterResult').textContent=off.length?off.map(x=>text[x]).join('\n'):'五块都在：模型知道做什么、按什么规则判断、怎样返回，以及不知道时怎么办。'});document.addEventListener('academy-artifact-change',()=>{}, {once:true});const examButton=document.getElementById('l5ExamButton');if(examButton){const obs=new MutationObserver(()=>{if(!examButton.disabled)A.set('promptV1',{task:'classify email',context:'company definitions',rules:'arrival time => refund_query',output:['intent','confidence','reason'],failure:'unknown when insufficient'})});obs.observe(examButton,{attributes:true,attributeFilter:['disabled']})}}
// Artifact ledger
const artifactDefs=[['businessRisk','第 1 课','业务风险与控制层'],['languageDecision','第 2 课','语言选型条件'],['tsSource','第 3 课','TypeScript 调用骨架'],['messages','第 4 课','完整 Messages 请求'],['promptV1','第 5 课','Prompt v1'],['classificationRules','第 6 课','分类规则与优先级'],['outputSchema','第 7 课','Zod Schema'],['fewShotExamples','第 8 课','Few-shot 示例集'],['evaluationReport','第 9 课','评估与回归报告']];function renderLedger(){const grid=document.getElementById('artifactLedgerGrid');if(!grid)return;grid.innerHTML=artifactDefs.map(([k,l,t])=>{const v=A.get(k);return `<article class="artifact-card ${v?'ready':''}"><span>${l}</span><b>${t}</b><small>${v?'✓ 已生成，将进入后续课程':'尚未生成'}</small></article>`}).join('')}document.addEventListener('academy-artifact-change',renderLedger);document.addEventListener('click',e=>{if(e.target.closest('[data-view="dashboard"]'))setTimeout(renderLedger,80)});document.getElementById('resetAllProgress')?.addEventListener('click',()=>{A.reset();setTimeout(renderLedger,50)});renderLedger();
})();
'''
